// Proves POST /api/route-plan honors the caller-supplied startTime (the value the
// client now derives from the forecast timeline). The same route is planned twice,
// 6 hours apart: geometry must be identical, depart/ETA must shift by exactly 6h,
// and the per-leg weather must be re-resolved to the forecast hour nearest the
// shifted arrival (proving the timeline drives the weather, not just the clock).
async function testRoutePlanStartTimeShift() {
  const BASE = 'http://localhost:3001';

  // A short, real Mediterranean route off Barcelona (origin + two waypoints)
  const points = [
    { lat: 41.35, lon: 2.17 },  // origin (boat)
    { lat: 41.55, lon: 2.55 },  // waypoint 1
    { lat: 41.80, lon: 3.10 }   // waypoint 2
  ];

  const SIX_HOURS_MS = 6 * 3600 * 1000;

  // Anchor on a whole hour so both start times land cleanly on forecast hours.
  // Use "now" floored to the hour so both departures are inside the forecast range.
  const t0 = Math.floor(Date.now() / 3600000) * 3600000;
  const t1 = t0 + SIX_HOURS_MS;

  // Helper: POST the route at a given startTime and return the parsed plan
  async function planAt(startTime) {
    const res = await fetch(BASE + '/api/route-plan', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ points, speed: 6, startTime })
    });
    assertEquals(res.status, 200, 'Route plan should return 200 for startTime ' + startTime);
    return res.json();
  }

  const planA = await planAt(t0);
  const planB = await planAt(t1);

  // --- Geometry is identical (only the time anchor changed) ---
  assertEquals(planA.legs.length, 2, 'Three points form two legs (A)');
  assertEquals(planB.legs.length, 2, 'Three points form two legs (B)');
  assertEquals(planB.totals.distanceNm, planA.totals.distanceNm, 'Distance is unchanged by start time');
  assertEquals(planB.totals.durationHours, planA.totals.durationHours, 'Duration is unchanged by start time');

  // --- The whole route shifts by exactly 6 hours ---
  // legs[0].departTimeMs equals the supplied start (first leg departs immediately)
  const departShift = planB.legs[0].departTimeMs - planA.legs[0].departTimeMs;
  assert(Math.abs(departShift - SIX_HOURS_MS) < 1000, 'Leg 0 departure should shift by ~6h, got ' + departShift);

  // totals.departTimeMs and totals.etaMs both shift by the same 6h
  const totalDepartShift = planB.totals.departTimeMs - planA.totals.departTimeMs;
  assert(Math.abs(totalDepartShift - SIX_HOURS_MS) < 1000, 'totals.departTimeMs should shift by ~6h, got ' + totalDepartShift);
  const etaShift = planB.totals.etaMs - planA.totals.etaMs;
  assert(Math.abs(etaShift - SIX_HOURS_MS) < 1000, 'ETA should shift by ~6h, got ' + etaShift);

  // Each leg's arrival also shifts by 6h (timing is anchored to the start)
  for (let i = 0; i < planA.legs.length; i++) {
    const legShift = planB.legs[i].arriveTimeMs - planA.legs[i].arriveTimeMs;
    assert(Math.abs(legShift - SIX_HOURS_MS) < 1000, 'Leg ' + i + ' arrival should shift by ~6h, got ' + legShift);
  }

  // --- Weather is re-resolved to the forecast hour nearest the shifted arrival ---
  // Both runs should resolve conditions for leg 0; the resolved forecast hour must
  // differ because the arrival moved 6 hours later (hourly forecast => ~6 hours apart).
  const condA = planA.legs[0].conditions;
  const condB = planB.legs[0].conditions;
  assert(condA && condA.time, 'Plan A leg 0 should resolve forecast conditions');
  assert(condB && condB.time, 'Plan B leg 0 should resolve forecast conditions');
  assertNotEquals(condB.time, condA.time, 'Re-resolved forecast hour should differ for the 6h-later arrival');

  // And the conditions timestamps themselves should be ~6h apart (sanity on re-resolution)
  const condShift = new Date(condB.time).getTime() - new Date(condA.time).getTime();
  assert(Math.abs(condShift - SIX_HOURS_MS) < 90 * 60 * 1000, 'Resolved forecast hour should move ~6h (within tolerance), got ' + condShift);
}
